mapper.select:
SELECT `库存编号` AS stockId, `废物类别` AS wasteCategory, `废物代码` AS wasteCode, `废物名称` AS wasteName, `当前重量` AS currentWeight, `辅助数量` AS auxQuantity, `辅助单位` AS auxUnit, `位置` AS location, `创建时间` AS createTime, `更新时间` AS updateTime, `危废条目编号` AS hazardousWasteItemId, `version` AS version FROM STOCK WHERE `废物代码` = #{wasteCode} AND `废物名称` = #{wasteName}
AND `危废条目编号` = #{hazardousWasteItemId}
AND `位置` = #{location}
ORDER BY `库存编号`
